import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { parsePdf } from '@/lib/pdf';
import { chunkText } from '@/lib/chunking';
import { generateEmbeddings } from '@/lib/embeddings';
import { generateAutomatedInsights } from '@/lib/insights';
import { v4 as uuidv4 } from 'uuid';

export const maxDuration = 60; // Allow longer execution on Vercel for PDF parsing

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get('file') as File;
    const workspaceId = formData.get('workspaceId') as string;

    if (!file) {
      return NextResponse.json({ error: 'No file uploaded' }, { status: 400 });
    }

    let finalWorkspaceId = workspaceId;
    if (!finalWorkspaceId) {
      // Find or create default workspace if unspecified
      let defaultWorkspace = await prisma.workspace.findFirst({ where: { name: 'Default' } });
      if (!defaultWorkspace) {
        defaultWorkspace = await prisma.workspace.create({ data: { name: 'Default' } });
      }
      finalWorkspaceId = defaultWorkspace.id;
    }

    const buffer = Buffer.from(await file.arrayBuffer());
    
    // Parse PDF
    const text = await parsePdf(buffer);
    if (!text || text.trim().length === 0) {
      return NextResponse.json({ error: 'Failed to extract text from PDF' }, { status: 400 });
    }

    // Create Paper record
    const paper = await prisma.paper.create({
      data: {
        title: file.name,
        workspaceId: finalWorkspaceId,
        url: file.name, // Local mockup placeholder instead of actual cloud URL
      }
    });

    // Chunk text
    const chunks = chunkText(text);
    
    // Generate embeddings in batches to stay within rate limits safely
    const BATCH_SIZE = 50;
    let chunksProcessed = 0;

    for (let i = 0; i < chunks.length; i += BATCH_SIZE) {
      const batchChunks = chunks.slice(i, i + BATCH_SIZE);
      const embeddings = await generateEmbeddings(batchChunks.map(c => c.content));
      
      // Store in DB with Raw SQL due to pgvector type limitations in current Prisma schema version
      for (let j = 0; j < batchChunks.length; j++) {
        const chunk = batchChunks[j];
        // Ensure standard array output for Postgres vector coercion
        const embedding = embeddings[j];
        const id = uuidv4();
        
        await prisma.$executeRaw`
          INSERT INTO "DocumentChunk" (id, "paperId", content, section, page, embedding)
          VALUES (${id}, ${paper.id}, ${chunk.content}, ${null}, ${null}, ${embedding}::vector)
        `;
      }
      chunksProcessed += batchChunks.length;
    }

    // Trigger insight generation asynchronously so we don't block the upload response
    generateAutomatedInsights(paper.id, text);

    return NextResponse.json({
      success: true,
      paperId: paper.id,
      chunksCount: chunksProcessed
    });

  } catch (error: any) {
    console.error('Upload error:', error);
    return NextResponse.json({ error: error.message || 'Internal server error' }, { status: 500 });
  }
}
