import { google } from '@ai-sdk/google';
import { openai } from '@ai-sdk/openai';

/**
 * Unified AI provider selection.
 * Prefers Gemini (Google) if the API key is provided, otherwise falls back to OpenAI.
 */

export function getChatModel() {
  if (process.env.GOOGLE_GENERATIVE_AI_API_KEY) {
    return google('gemini-1.5-pro-latest');
  }
  return openai('gpt-4o');
}

export function getInsightModel() {
  if (process.env.GOOGLE_GENERATIVE_AI_API_KEY) {
    return google('gemini-1.5-flash-latest');
  }
  return openai('gpt-4o-mini');
}

export function getEmbeddingModel() {
  if (process.env.GOOGLE_GENERATIVE_AI_API_KEY) {
    // text-embedding-004 has 768 dimensions
    return google.textEmbeddingModel('text-embedding-004');
  }
  // text-embedding-3-small has 1536 dimensions
  return openai.embedding('text-embedding-3-small');
}

export const isUsingGemini = !!process.env.GOOGLE_GENERATIVE_AI_API_KEY;
